(1833, '_transient_dash_v2_a5a61dcab273495c31cd79aafebbdc74', '<div class=\"rss-widget\"><ul><li><a class=\'rsswidget\' href=\'https://vi.wordpress.org/2025/05/20/nha-trang-wordpress-meetup-2025/\'>Nha Trang WordPress Meetup 2025</a></li><li><a class=\'rsswidget\' href=\'https://vi.wordpress.org/2024/08/25/hinh-anh-su-kien-nha-trang-wordpress-meetup-25-08-2024/\'>Hình ảnh sự kiện Nha Trang WordPress Meetup 25/08/2024</a></li></ul></div><div class=\"rss-widget\"><ul><li><a class=\'rsswidget\' href=\'https://wptavern.com/podcast/172-reyes-martinez-and-hector-de-prada-on-website-maintenance-for-wordpress-agencies-and-freelancers\'>WPTavern: #172 – Reyes Martínez and Héctor De Prada on Website Maintenance for WordPress Agencies and Freelancers</a></li><li><a class=\'rsswidget\' href=\'https://openchannels.fm/rebrand-amplifying-with-the-open-source-reach-show/\'>Do The Woo Community: Rebrand: Amplifying with the Open Source Reach Show</a></li><li><a class=\'rsswidget\' href=\'https://openchannels.fm/thanks-to-the-repository-for-sharing-our-next-chapter/\'>Do The Woo Community: Thanks to The Repository for Sharing Our Next Chapter</a></li></ul></div>', 'off'),
