(8003, 1043, 'giới_thiệu', 'Ông Nguyễn Hữu Phát nhận học vị Tiến sĩ Điện Tử viễn thông năm 2012 của Viện công nghệ Shibaura –Nhật Bản. Hiện tại Ông Nguyễn Hữu Phát là Giảng viên cao cấp tại Khoa Điện tử, Trường Điện - Điện tử, Đại học Bách khoa Hà Nội. Các hướng nghiên cứu quan tâm hiện tại bao gồm: xử lý ảnh/video, mạng cảm biến không dây, hệ thống nhúng.'),
(8004, 1043, '_giới_thiệu', 'field_68348cfcea9b4'),
(8005, 1043, 'cac_cong_trinh_khoa_học_tieu_biểu', '<ul>\r\n 	<li>P. Nguyen Huu, N. Nguyen Thi and T. P. Ngoc, \"Proposing Posture Recognition System Combining MobilenetV2 and LSTM for Medical Surveillance,\" in IEEE Access, vol. 10, pp. 1839-1849, 2022, doi: 10.1109/ACCESS.2021.3138778.</li>\r\n</ul>\r\n<ul>\r\n 	<li>P. N. Huu, Q. T. Minh, H. L. The, \"An ANN-based gesture recognition algorithm for smart-home applications,\" KSII Transactions on Internet and Information Systems, vol. 14, no. 5, pp. 1967-1983, 2020. DOI: 10.3837/tiis.2020.05.006.</li>\r\n</ul>\r\n<ul>\r\n 	<li>C. T. Phan, D. D. Pham, H. V. Tran, T. V. Tran, P. N. Huu, \"Applying the IoT platform and green wave theory to control intelligent traffic lights system for urban areas in Vietnam,\" KSII Transactions on Internet and Information Systems, vol. 13, no. 1, pp. 34-51, 2019. DOI: 10.3837/tiis.2019.01.003.</li>\r\n</ul>\r\n<ul>\r\n 	<li>Huu, Phat Nguyen, Anh, Bang Nguyen, Minh, Quang Tran, Proposing Smart System for Detecting and Monitoring Vehicle Using Multiobject Multicamera Tracking, International Journal of Digital Multimedia Broadcasting, 2024, 6667738, 14 pages, 2024. https://doi.org/10.1155/2024/6667738</li>\r\n</ul>\r\n<ul>\r\n 	<li>Nguyen Huu, Phat, Tran-Quang, Vinh, Miyoshi, Takumi, Video Compression Schemes Using Edge Feature on Wireless Video Sensor Networks, Journal of Electrical and Computer Engineering, 2012, 421307, 20 pages, 2012. https://doi.org/10.1155/2012/421307</li>\r\n</ul>\r\n<ul>\r\n 	<li>Huu, Phat Nguyen, Thi Thu, Huong Nguyen, Minh, Quang Tran, Proposing a Recognition System of Gestures Using MobilenetV2 Combining Single Shot Detector Network for Smart-Home Applications, Journal of Electrical and Computer Engineering, 2021, 6610461, 18 pages, 2021. https://doi.org/10.1155/2021/6610461</li>\r\n</ul>\r\n<ul>\r\n 	<li>Huu, Phat Nguyen, Phung Ngoc, Tan, Hand Gesture Recognition Algorithm Using SVM and HOG Model for Control of Robotic System, Journal of Robotics, 2021, 3986497, 13 pages, 2021. https://doi.org/10.1155/2021/3986497</li>\r\n</ul>\r\n<ul>\r\n 	<li>Huu, Phat Nguyen, Thi Thu, Huong Nguyen, Minh, Quang Tran, Proposing a Recognition System of Gestures Using MobilenetV2 Combining Single Shot Detector Network for Smart-Home Applications, Journal of Electrical and Computer Engineering, 2021, 6610461, 18 pages, 2021. https://doi.org/10.1155/2021/6610461</li>\r\n</ul>\r\n<ul>\r\n 	<li>Han, Trong-Thanh, Nguyen Van, Hinh, Nguyen Huu, Phat, Denoising Method for MRI Images Using Modified BM3D Filter with Complex Network and Artificial Neural Networks, Journal of Electrical and Computer Engineering, 2024, 2606485, 9 pages, 2024. https://doi.org/10.1155/2024/2606485</li>\r\n</ul>\r\n<ul>\r\n 	<li>P. N. Huu, V. T. Quang, and T. Miyoshi, “Low-Complexity and Energy-Efficient Algorithms on Image Compression for Wireless Sensor Networks,” IEICE Transactions on Communications, E93-B (12), 3438-3447, 2010</li>\r\n</ul>'),
