(8167, 1055, 'giảng_dạy', '<ul>\r\n 	<li>ET2050: Lý thuyết mạch</li>\r\n</ul>\r\n<ul>\r\n 	<li>ET2072:Lý thuyết thông tin</li>\r\n</ul>\r\n<ul>\r\n 	<li>ET3230: Xử lý ảnh</li>\r\n</ul>\r\n<ul>\r\n 	<li>ET2000: Nhập môn Điện tử viễn thông</li>\r\n</ul>\r\n<ul>\r\n 	<li>ET3262: Tư duy công nghệ và thiết kế kỹ thuật</li>\r\n</ul>\r\n<ul>\r\n 	<li>ET6141: Hệ thống thông tin đa phương tiện</li>\r\n</ul>'),
