(105, 1, '2025-05-12 03:48:16', '2025-05-12 03:48:16', '<div class=\"clearfix\">\r\n\r\n<img src=\"https://seee.hust.edu.vn/uploads/seee/news/2025_05/anh-dai-dien-website.png\" alt=\"Le trao bang TN\" />\r\n<figure class=\"article center\"><figcaption>\r\n<div class=\"clearfix\" style=\"text-align: center;\">\r\n<figure class=\"article center\"><figcaption>Le trao bang TN</figcaption></figure>\r\n</div>\r\n<div id=\"news-bodyhtml\" class=\"bodytext margin-bottom-lg\">\r\n<div style=\"text-align: center;\"><strong>KẾ HOẠCH PHÁT BẰNG VÀ HỒ SƠ TỐT NGHIỆP KỲ 2024.1B\r\nTRƯỜNG ĐIỆN - ĐIỆN TỬ</strong></div>\r\n</div>\r\n</figcaption></figure>\r\n</div>\r\n<div id=\"news-bodyhtml\" class=\"bodytext margin-bottom-lg\">\r\n<ol>\r\n 	<li>ĐỊA ĐIỂM:     Hội trường C2, Hội thảo C2</li>\r\n 	<li>THỜI GIAN:     Từ 6h30 – 11h00 sáng chủ nhật, ngày 11 tháng 5 năm 2025</li>\r\n</ol>\r\n<div><strong>THỦ TỤC CẦN HOÀN THÀNH TRƯỚC KHI ĐẾN NHẬN BẰNG:</strong></div>\r\n<ol>\r\n 	<li>Hoàn thành khảo sát tốt nghiệp theo hướng dẫn của Ban Công tác sinh viên</li>\r\n 	<li>Thanh toán các công nợ (nếu có): Học phí, Sách thư viện.</li>\r\n</ol>\r\n<div><strong> GIẤY TỜ CẦN MANG THEO: </strong></div>\r\n<ol>\r\n 	<li>Thẻ sinh viên</li>\r\n 	<li>Căn cước/ VNeID (cập nhật mức 2)</li>\r\n</ol>\r\n<div><strong>TRÌNH TỰ BUỔI PHÁT BẰNG, HỒ SƠ TỐT NGHIỆP:</strong></div>\r\n<ol>\r\n 	<li> 6h30 sinh viên tham dự Lễ tốt nghiệp cần có mặt để mượn lễ phục tốt nghiệp do Hội Sinh viên Đại học tổ chức sau đó vào Hội trường C2 ngồi đúng vị trí do Ban tổ chức sắp xếp.</li>\r\n</ol>\r\n<em> Lưu ý: mang theo Căn cước hoặc giấy tờ cá nhân khác để mượn lễ phục tốt nghiệp; phí mượn lễ phục trả trực tiếp cho Hội Sinh viên khi mượn.</em>\r\n<ol start=\"2\">\r\n 	<li>Sau khi dự Lễ nhận bằng, di chuyển sang Phòng Hội thảo C2 nhận Hồ sơ tốt nghiệp theo hướng dẫn của Sinh viên tình nguyện (Mang theo Thẻ SV hoặc Căn cước hoặc VNeID)</li>\r\n</ol>\r\n<div><strong>Nhận hồ sơ sau ngày 11/5/2025: </strong>\r\nSinh viên đến Văn phòng Trường tại phòng E605 nhà C7 nhận Bằng tốt nghiệp và phụ lục văn bằng, sau đó đến Phòng 103-C1 nhận Hồ sơ sinh viên.</div>\r\n</div>', 'Kế hoạch phát bằng và hồ sơ tốt nghiệp kỳ 2024.1B - Trường Điện - Điện tử', '', 'publish', 'open', 'open', '', '105', '', '', '2025-05-12 03:51:58', '2025-05-12 03:51:58', '', 0, 'http://web-hust.test/?post_type=tin&#038;p=105', 0, 'tin', '', 0),
