(167, 1, '2025-05-12 15:49:55', '2025-05-12 15:49:55', '<strong>1. CHƯƠNG TRÌNH ĐÀO TẠO ĐẠI HỌC</strong>\r\n\r\n<strong>1.1. Các chương trình đào tạo tích hợp Cử nhân - Thạc sỹ khoa học</strong>\r\n<ul>\r\n 	<li><a href=\"https://seee.hust.edu.vn/uploads/seee/dao-tao/2022/03/ctdt-dien-1-ee1-program-final.137618.10284.pdf\">Chương trình tích hợp Cử nhân - thạc sỹ Kỹ thuật Điện</a></li>\r\n 	<li><a href=\"https://seee.hust.edu.vn/uploads/seee/education/2025_03/ee2_program_final_printed_may2020new.pdf\">Chương trình tích hợp Cử nhân - thạc sỹ Kỹ thuật Điều khiển - Tự động hóa</a></li>\r\n 	<li><a href=\"https://seee.hust.edu.vn/uploads/seee/dao-tao/2022/03/dtvt-1-02-ctdt-cu-nhan-thac-sy-kh-ktdt-final-14072020.137618.10285.pdf\">Chương trình tích hợp Cử nhân - thạc sỹ Kỹ thuật Điện tử</a></li>\r\n 	<li><a href=\"https://seee.hust.edu.vn/uploads/seee/dao-tao/2022/03/dtvt-2-02-ctdt-cu-nhan-thac-sy-kh-ktvt-final-14072020.137618.10286.pdf\">Chương trình tích hợp Cử nhân - thạc sỹ Kỹ thuật Viễn thông</a></li>\r\n 	<li><a href=\"https://seee.hust.edu.vn/uploads/seee/dao-tao/2022/03/dtvt-3-02-ctdt-cu-nhan-thac-sy-kh-ktys-final-14072020.137618.10287.pdf\">Chương trình tích hợp Cử nhân - thạc sỹ Kỹ thuật Y sinh</a></li>\r\n</ul>\r\n<strong>1.2. Các chương trình đào tạo kỹ sư 160TC áp dụng cho K62, K63, K64</strong>\r\n<ul>\r\n 	<li><a href=\"https://seee.hust.edu.vn/uploads/seee/dao-tao/2022/03/ctdt-dien-3-ee2-ks-program-final.137618.10289.pdf\">Chương trình kỹ sư Kỹ thuật Điều khiển và Tự động hóa</a></li>\r\n 	<li><a href=\"https://seee.hust.edu.vn/uploads/seee/dao-tao/2023/06/ctdt-dien-2-ee1-ks-program-final-160tc.293370.11743.pdf\">Chương trình kỹ sư Kỹ thuật Điện</a></li>\r\n 	<li><a href=\"https://seee.hust.edu.vn/uploads/seee/dao-tao/2022/03/dtvt-4-ctdt-ky-su-161tc-ktdtvt-de-cuong-chi-tiet-update-062021.137618.10288.pdf\">Chương trình kỹ sư Kỹ thuật Điện tử - Viễn thông</a></li>\r\n</ul>\r\n<strong>CÁC CHƯƠNG TRÌNH ĐÀO TẠO</strong>\r\n<figure class=\"table\">\r\n<div class=\"table-responsive table-responsive-all\">\r\n<table class=\"ck-table-resized\"><colgroup><col /><col /><col /></colgroup>\r\n<tbody>\r\n<tr>\r\n<td>1</td>\r\n<td>Kỹ thuật Điện tử - Viễn thông\r\n(Chương trình chuẩn)</td>\r\n<td><a href=\"https://seee.hust.edu.vn/vi/dao-tao/dao-tao-dai-hoc/et1-ky-thuat-dien-tu-vien-thong-287931.html\">ET1</a></td>\r\n</tr>\r\n<tr>\r\n<td>2</td>\r\n<td>Kỹ thuật Y sinh\r\n(Chương trình chuẩn)</td>\r\n<td><a href=\"https://seee.hust.edu.vn/vi/dao-tao/dao-tao-dai-hoc/et2-ky-thuat-y-sinh-287932.html\">ET2</a></td>\r\n</tr>\r\n<tr>\r\n<td>3</td>\r\n<td>Kỹ thuật Điện tử - Viễn thông\r\n(CT tiên tiến)</td>\r\n<td><a href=\"https://seee.hust.edu.vn/vi/dao-tao/dao-tao-dai-hoc/et-e4-ky-thuat-dien-tu-vien-thong-cttt-287933.html\">ET-E4</a></td>\r\n</tr>\r\n<tr>\r\n<td>4</td>\r\n<td>Kỹ thuật Y sinh\r\n(CT tiên tiến)</td>\r\n<td><a href=\"https://seee.hust.edu.vn/vi/dao-tao/dao-tao-dai-hoc/et-e5-ky-thuat-y-sinh-cttt-287934.html\">ET-E5</a></td>\r\n</tr>\r\n<tr>\r\n<td>5</td>\r\n<td>Hệ thống nhúng thông minh và IoT\r\n(CT tiên tiến)</td>\r\n<td><a href=\"https://seee.hust.edu.vn/vi/dao-tao/dao-tao-dai-hoc/et-e9-he-thong-nhung-thong-minh-va-iot-287935.html\">ET-E9</a></td>\r\n</tr>\r\n<tr>\r\n<td>6</td>\r\n<td>Truyền thông số và Kỹ thuật đa phương tiện\r\n(CT tiên tiến)</td>\r\n<td><a href=\"https://seee.hust.edu.vn/vi/dao-tao/dao-tao-dai-hoc/et-e16-truyen-thong-so-va-ky-thuat-da-phuong-tien-287936.html\">ET-E16</a></td>\r\n</tr>\r\n<tr>\r\n<td>7</td>\r\n<td>Chương trình tài năng ĐTVT\r\nET-TN</td>\r\n<td><a href=\"https://seee.hust.edu.vn/vi/dao-tao/dao-tao-dai-hoc/et-tn-chuong-trinh-tai-nang-dtvt-287937.html\">ET-TN</a></td>\r\n</tr>\r\n<tr>\r\n<td>8</td>\r\n<td>Điện tử - Viễn thông - hợp tác với ĐH Leibniz Hannover (Đức)</td>\r\n<td><a href=\"https://seee.hust.edu.vn/vi/dao-tao/dao-tao-dai-hoc/et-luh-dien-tu-vien-thong-leibniz-hannover-duc-287923.html\">ET-LUH</a></td>\r\n</tr>\r\n<tr>\r\n<td>9</td>\r\n<td>Kỹ thuật Điện\r\n(Chương trình chuẩn)</td>\r\n<td><a href=\"https://seee.hust.edu.vn/vi/dao-tao/dao-tao-dai-hoc/ee1-ky-thuat-dien-287925.html\">EE1</a></td>\r\n</tr>\r\n<tr>\r\n<td>10</td>\r\n<td>Kỹ thuật Điều khiển - Tự động hoá\r\n(Chương trình chuẩn)</td>\r\n<td><a href=\"https://seee.hust.edu.vn/vi/dao-tao/dao-tao-dai-hoc/ee2-ky-thuat-dieu-khien-va-tu-dong-hoa-287926.html\">EE2</a></td>\r\n</tr>\r\n<tr>\r\n<td>11</td>\r\n<td>Hệ thống điện và năng lượng tái tạo\r\n(CT tiên tiến)</td>\r\n<td><a href=\"https://seee.hust.edu.vn/vi/dao-tao/dao-tao-dai-hoc/ee-e18-he-thong-dien-va-nang-luong-tai-tao-287928.html\">EE-E18</a></td>\r\n</tr>\r\n<tr>\r\n<td>12</td>\r\n<td>Kỹ thuật Điều khiển - Tự động hoá\r\n(CT tiên tiến)</td>\r\n<td><a href=\"https://seee.hust.edu.vn/vi/dao-tao/dao-tao-dai-hoc/ee-e8-ky-thuat-dieu-khien-tu-dong-hoa-cttt-287927.html\">EE-E8</a></td>\r\n</tr>\r\n<tr>\r\n<td>13</td>\r\n<td>Tin học công nghiệp và Tự động hóa\r\n(Chương trình Việt - Pháp PFIEV)</td>\r\n<td><a href=\"https://seee.hust.edu.vn/vi/dao-tao/dao-tao-dai-hoc/ee-ep-tin-hoc-cong-nghiep-va-tu-dong-hoa-287929.html\">EE-EP</a></td>\r\n</tr>\r\n<tr>\r\n<td>14</td>\r\n<td>Cử nhân Tài năng Điều khiển – Tự động hóa\r\n(Chương trình tài năng)</td>\r\n<td><a href=\"https://seee.hust.edu.vn/vi/dao-tao/dao-tao-dai-hoc/ee-tn-chuong-trinh-tai-nang-tu-dong-hoa-287930.html\">EE - TN</a></td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div></figure>', 'Đại học', '', 'publish', 'open', 'open', '', 'dai-hoc', '', '', '2025-05-13 02:46:49', '2025-05-13 02:46:49', '', 0, 'http://web-hust.test/?post_type=training&#038;p=167', 0, 'training', '', 0),
