(173, 1, '2025-05-12 15:51:39', '2025-05-12 15:51:39', '<strong>Các chương trình đào tạo kỹ sư chuyên sâu đặc thù 180TC áp dụng từ K65</strong>\r\n<ul>\r\n 	<li>Chương trình kỹ sư Kỹ thuật Điện</li>\r\n 	<li><a href=\"https://seee.hust.edu.vn/documents/137618/0/CTDT+DIEN+3+-+EE2++program+180+TC+-+15_Oct_2021+new.pdf/3e9ae4aa-b914-47e1-9e8f-161321aa742a\">Chương trình kỹ sư Kỹ thuật Điều khiển - Tự động hóa</a></li>\r\n 	<li><a href=\"https://seee.hust.edu.vn/documents/264314/293370/DTVT+7+-+Khung+CT%C4%90T+K%E1%BB%B9+s%C6%B0+180+TC_KT+%C4%90i%E1%BB%87n+t%E1%BB%AD_Submit_062021.pdf/0fb052a8-33f1-43cd-866e-06dbd82f7b59\">Chương trình kỹ sư Kỹ thuật Điện tử</a></li>\r\n 	<li><a href=\"https://seee.hust.edu.vn/documents/264314/293370/DTVT+5+-+Khung+CT%C4%90T+K%E1%BB%B9+s%C6%B0+180+TC_KT+Vi%E1%BB%85n+th%C3%B4ng_Submit_062021.pdf/b4901905-f48e-4667-b6ce-66103dbb6fb1\">Chương trình kỹ sư Kỹ thuật Viễn thông</a></li>\r\n 	<li><a href=\"https://seee.hust.edu.vn/documents/264314/293370/DTVT+6+-+Khung+CT%C4%90T+K%E1%BB%B9+s%C6%B0+180+TC_KT+Y+sinh_Submit_062021.pdf/98ff4da6-36f1-4242-a902-dbb3efb073d2\">Chương trình kỹ sư Kỹ thuật Y sinh</a></li>\r\n</ul>', 'Kỹ sư chuyên sâu đặc thù', '', 'publish', 'open', 'open', '', 'ky-su-chuyen-sau-dac-thu', '', '', '2025-05-13 02:50:29', '2025-05-13 02:50:29', '', 0, 'http://web-hust.test/?post_type=training&#038;p=173', 0, 'training', '', 0),
