(325, 1, '2025-05-14 03:16:29', '2025-05-14 03:16:29', '<table class=\"ck-table-resized\">\r\n<tbody>\r\n<tr>\r\n<td colspan=\"3\"><strong>GIỚI THIỆU</strong></td>\r\n</tr>\r\n<tr>\r\n<td colspan=\"3\">Nhóm chuyên môn Thiết bị đóng cắt và Bảo vệ có nhiệm vụ phối hợp với Khoa Điện và Trung tâm đào tạo trong trường Điện-Điện tử triển khai các nội dung giảng dạy lý thuyết, bài tập và thí nghiệm cho các môn học Thiết bị đóng cắt và bảo vệ, Khí cụ Điện, Thiết bị đóng cắt hiện đại, Thiết kế thiết bị đóng cắt cho toàn Khoa hoặc chuyên ngành Thiết bị điện-điện tử. Nhóm thực hiện công tác đào tạo dưới sự quản lý của Khoa Điện bao gồm giảng dạy, soạn đề thi, đáp án, chấm thi, nhập điểm,... ngoài ra nhóm còn triển khai các nhiệm vụ đề cương, bài giảng, giáo trình, học liệu số,...</td>\r\n</tr>\r\n<tr>\r\n<td colspan=\"3\"><strong>CÁC CON SỐ</strong></td>\r\n</tr>\r\n<tr>\r\n<td colspan=\"3\">Nhóm chuyên môn Thiết bị đóng cắt và Bảo vệ có 6 thành viên bao gồm 05 cán bộ giảng dạy và 01 cán bộ kỹ thuật. Nhóm chuyên môn Thiết bị đóng cắt còn phối hợp với Trung tâm thí nghiệm thực hành 01 PTN Khí cụ điện.</td>\r\n</tr>\r\n<tr>\r\n<td colspan=\"3\"><strong>CÁC MÔN HỌC</strong></td>\r\n</tr>\r\n<tr>\r\n<td>EE3242</td>\r\n<td>Khí cụ điện (Fundamental Switchgear). Học phần này cung cấp cho người học các kiến thức cơ bản về cơ sở lý thuyết khí cụ điện về phát nóng, hồ quang điện, lực điện động, tiếp xúc điện, tiếp điểm và nam châm điện và ứng dụng.</td>\r\n<td>Hệ cử nhân</td>\r\n</tr>\r\n<tr>\r\n<td>EE3245</td>\r\n<td>Thiết bị đóng cắt và bảo vệ (Switchgear and Protective Devices). Học phần này cung cấp cho người học các kiến thức cơ bản và chuyên sâu về cấu tạo, nguyên lý hoạt động và phạm vi ứng dụng của các thiết bị đóng cắt và bảo vệ đóng cắt, bảo vệ và điều khiển trong hệ thống điện từ cấp hạ áp (dưới 1000V) đến cấp cao áp (trên 1000V).</td>\r\n<td>Hệ cử nhân</td>\r\n</tr>\r\n<tr>\r\n<td>EE4090</td>\r\n<td>Khí cụ điện cao áp (High Voltage Switchgear)</td>\r\n<td>Hệ cử nhân/kỹ sư/thạc sĩ</td>\r\n</tr>\r\n<tr>\r\n<td>EE4562</td>\r\n<td>Thiết kế thiết bị đóng cắt và bảo vệ</td>\r\n<td>Hệ cử nhân/kỹ sư/thạc sĩ</td>\r\n</tr>\r\n<tr>\r\n<td>EE4565</td>\r\n<td>Thiết bị đóng cắt hiện đại</td>\r\n<td>Hệ cử nhân/kỹ sư/thạc sĩ</td>\r\n</tr>\r\n<tr>\r\n<td>EE5432</td>\r\n<td>Phương pháp tính toán điện từ trường</td>\r\n<td>Hệ cử nhân /KSCQ/Thạc sĩ khoa học</td>\r\n</tr>\r\n<tr>\r\n<td>EE6564</td>\r\n<td>Thiết kế thiết bị đóng cắt và bảo vệ (HP bổ sung cao học)</td>\r\n<td>Thạc sĩ khoa học</td>\r\n</tr>\r\n</tbody>\r\n</table>', 'Nhóm chuyên môn Thiết bị đóng cắt và bảo vệ', '', 'inherit', 'closed', 'closed', '', '324-revision-v1', '', '', '2025-05-14 03:16:29', '2025-05-14 03:16:29', '', 324, 'http://web-hust.test/?p=325', 0, 'revision', '', 0),
(326, 1, '2025-05-14 03:17:09', '2025-05-14 03:17:09', 'Khoa Tự động hóa được thành lập ngày 18/11/2021 trong bối cảnh Trường Đại học Bách khoa Hà Nội thay đổi mô hình quản trị sang mô hình “Trường trong Đại học” căn cứ theo các quy định của Luật giáo dục được ban hành trước đó. Khoa Tự động hóa là một trong bốn khoa chuyên môn của Trường Điện – Điện tử, được tái cấu trúc từ ba bộ môn chuyên môn là Kỹ thuật đo &amp; Tin học công nghiệp, Điều khiển tự động và Tự động hóa công nghiệp với 65 cán bộ giảng viên trong đó có 02 GS, 23 PGS và 25 TS. Phần lớn cán bộ giảng viên của Khoa được đào tạo bài bản tại các đại học uy tín trên thế giới.\r\nKhoa Tự động hóa hàng năm tuyển sinh khoảng 650 sinh viên cho 4 chương trình đào tạo thuộc ngành Kỹ thuật Điều khiển và Tự động hóa:\r\n<ul>\r\n 	<li>Chương trình chuẩn Kỹ thuật Điều khiển và Tự động hóa (EE2): 500 sv/1 năm</li>\r\n 	<li>Chương trình tiên tiến Điều khiển và Tự động hóa (EE-E8): 120 sv/1 năm</li>\r\n 	<li>Chương trình Việt – Pháp PFIEV Tin học công nghiệp và Tự động hóa (EE-EP): 40 sv/1 năm</li>\r\n 	<li>Chương trình tài năng Điều khiển và Tự động hóa (EE-TN): 40 sv/1 năm</li>\r\n</ul>\r\nHiện nay, Khoa Tự động hóa phụ trách 8 nhóm chuyên môn liên quan đến các học phần cơ sở ngành, cơ sở cốt lõi và chuyên ngành Kỹ thuật Điều khiển và Tự động hóa:\r\n<ul>\r\n 	<li>Cơ sở Lý thuyết điều khiển tự động</li>\r\n 	<li>Điện tử công suất</li>\r\n 	<li>Truyền động điện</li>\r\n 	<li>Cảm biến và Kỹ thuật đo lường</li>\r\n 	<li>Tự động hóa công nghiệp</li>\r\n 	<li>PLC và ứng dụng</li>\r\n 	<li>Điều khiển và Ứng dụng</li>\r\n 	<li>Điều khiển nâng cao và điều khiển thông minh</li>\r\n</ul>\r\nBan lãnh đạo Khoa Tự động hóa gồm có:\r\n<ul>\r\n 	<li>Trưởng khoa: <a href=\"https://seee.hust.edu.vn/vi/suborgans/person/Khoa-Tu-dong-hoa-5/TS-Pham-Viet-Phuong-81/\">TS. Phạm Việt Phương</a></li>\r\n 	<li>Phó trưởng khoa: <a href=\"https://seee.hust.edu.vn/vi/suborgans/person/Khoa-Tu-dong-hoa-5/TS-Nguyen-Thu-Ha-50/\">TS. Nguyễn Thu Hà</a></li>\r\n 	<li>Phó trưởng khoa: <a href=\"https://seee.hust.edu.vn/vi/suborgans/person/Khoa-Tu-dong-hoa-5/PGS-Duong-Minh-Duc-62/\">PGS. TS. Dương Minh Đức</a></li>\r\n</ul>', 'Giới thiệu chung', '', 'publish', 'open', 'open', '', 'gioi-thieu-chung-2', '', '', '2025-05-14 03:17:09', '2025-05-14 03:17:09', '', 0, 'http://web-hust.test/?post_type=center-department&#038;p=326', 0, 'center-department', '', 0),
