(332, 1, '2025-05-14 03:18:48', '2025-05-14 03:18:48', '<table width=\"1192\"><colgroup><col width=\"59\" /><col width=\"529\" /><col width=\"231\" /><col width=\"120\" /><col width=\"253\" /></colgroup>\r\n<tbody>\r\n<tr>\r\n<td class=\"xl67\">STT</td>\r\n<td class=\"xl68\">Môn học</td>\r\n<td class=\"xl67\">Cán bộ</td>\r\n<td class=\"xl68\">Phòng làm việc</td>\r\n<td class=\"xl67\">Email</td>\r\n</tr>\r\n<tr>\r\n<td class=\"xl69\">1</td>\r\n<td class=\"xl70\" align=\"left\">ET4611 Điện tử công suất</td>\r\n<td class=\"xl71\" align=\"left\">PGS. TS. Trần Trọng Minh</td>\r\n<td class=\"xl72\"></td>\r\n<td class=\"xl73\" align=\"left\"><a href=\"mailto:minh.trantrong@hust.edu.vn\">minh.trantrong@hust.edu.vn</a></td>\r\n</tr>\r\n<tr>\r\n<td class=\"xl69\">2</td>\r\n<td class=\"xl70\" align=\"left\">EE3410 Điện tử công suất</td>\r\n<td class=\"xl71\" align=\"left\">PGS. TS. Nguyễn Văn Khang</td>\r\n<td class=\"xl71\"></td>\r\n<td class=\"xl73\" align=\"left\"><a href=\"mailto:khang.nguyenvan@hust.edu.vn\">khang.nguyenvan@hust.edu.vn</a></td>\r\n</tr>\r\n<tr>\r\n<td class=\"xl69\">3</td>\r\n<td class=\"xl70\" align=\"left\">EE3410E Điện tử công suất</td>\r\n<td class=\"xl71\" align=\"left\">TS. Phạm Nguyễn Thanh Loan</td>\r\n<td class=\"xl71\"></td>\r\n<td class=\"xl73\" align=\"left\"><a href=\"mailto:loan.phamnguyenthanh@hust.edu.vn\">loan.phamnguyenthanh@hust.edu.vn</a></td>\r\n</tr>\r\n<tr>\r\n<td class=\"xl69\">4</td>\r\n<td class=\"xl70\" align=\"left\">EE4331 Điều khiển Điện tử công suất</td>\r\n<td class=\"xl71\" align=\"left\">TS. Hàn Huy Dũng</td>\r\n<td class=\"xl71\"></td>\r\n<td class=\"xl73\" align=\"left\"><a href=\"mailto:dung.hanhuy@hust.edu.vn\">dung.hanhuy@hust.edu.vn</a></td>\r\n</tr>\r\n<tr>\r\n<td class=\"xl69\">5</td>\r\n<td class=\"xl70\" align=\"left\">EE5426 Thiết kế hệ thống biến đổi điện năng</td>\r\n<td class=\"xl71\" align=\"left\">PGS.TS. Vũ Hoàng Phương</td>\r\n<td class=\"xl71\"></td>\r\n<td class=\"xl73\" align=\"left\"><a href=\"mailto